    {
      "type": 12,
      "content": {
        "version": "NotebookGroup/1.0",
        "groupType": "editable",
        "title": "Ingestion (GBs per day)",
        "items": [
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "Usage\n| where IsBillable == true\n| project TimeGenerated, DataType, Quantity\n| summarize Ingestion_GB=sum(Quantity)/1024 by bin(TimeGenerated, 1d), DataType",
              "size": 2,
              "timeContextFromParameter": "TimePicker",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "barchart",
              "chartSettings": {
                "createOtherGroup": 50
              }
            },
            "name": "chart-total"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "Usage\n| where IsBillable == true\n| project TimeGenerated, DataType, Quantity\n| summarize Ingestion_GB=round(sum(Quantity)/1024,2), Ingestion_TB=round(sum(Quantity)/1048576,6) by DataType\n| extend Total_GB = toscalar(Usage | where IsBillable==true | summarize sum(Quantity)/1024)\n| extend Pct_of_Total=round(Ingestion_GB/iif(Total_GB==0.0,1.0,Total_GB)*100,1)\n| project DataType, Ingestion_GB, Ingestion_TB, Pct_of_Total\n| order by Ingestion_GB desc",
              "size": 3,
              "title": "Click a row below to drill down  ▼  (sorted by size)",
              "timeContextFromParameter": "TimePicker",
              "exportFieldName": "DataType",
              "exportParameterName": "SelectedDataType",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "table",
              "gridSettings": {
                "formatters": [
                  {
                    "columnMatch": "Ingestion_GB",
                    "formatter": 4,
                    "formatOptions": {
                      "palette": "blue",
                      "showBorder": false
                    },
                    "numberFormat": {
                      "unit": 0,
                      "options": {
                        "style": "decimal",
                        "maximumFractionDigits": 2
                      }
                    }
                  },
                  {
                    "columnMatch": "Ingestion_TB",
                    "formatter": 4,
                    "formatOptions": {
                      "palette": "orange",
                      "showBorder": false
                    },
                    "numberFormat": {
                      "unit": 0,
                      "options": {
                        "style": "decimal",
                        "maximumFractionDigits": 6
                      }
                    }
                  },
                  {
                    "columnMatch": "Pct_of_Total",
                    "formatter": 4,
                    "formatOptions": {
                      "palette": "green",
                      "showBorder": false
                    },
                    "numberFormat": {
                      "unit": 0,
                      "options": {
                        "style": "decimal",
                        "maximumFractionDigits": 1
                      }
                    }
                  },
                  {
                    "columnMatch": "EventCount",
                    "formatter": 4,
                    "formatOptions": {
                      "palette": "blue",
                      "showBorder": false
                    }
                  }
                ],
                "filter": true,
                "sortBy": [
                  {
                    "itemKey": "Ingestion_GB",
                    "sortOrder": 2
                  }
                ],
                "rowLimit": 50,
                "labelSettings": []
              }
            },
            "name": "selector-grid-DataType"
          },
          {
            "type": 1,
            "content": {
              "json": "### Drilldown: **{SelectedDataType}** — Daily Spike Analysis\n\nShowing daily ingestion vs. rolling average. SpikeStatus flags days >1.5× or >2× average. Use the **⬇ Export** button (top-right of grid) to download CSV for the cloud team.",
              "style": "info"
            },
            "conditionalVisibility": {
              "parameterName": "SelectedDataType",
              "comparison": "isNotEqualTo",
              "value": ""
            },
            "name": "hint-SelectedDataType"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "let avgDailyGB = toscalar(\n  Usage\n  | where IsBillable == true\n  | where DataType == '{SelectedDataType}'\n  | summarize DailyGB = sum(Quantity)/1024 by bin(TimeGenerated, 1d)\n  | summarize avg(DailyGB)\n);\nUsage\n| where IsBillable == true\n| where DataType == '{SelectedDataType}'\n| summarize Ingestion_MB=round(sum(Quantity),2), Ingestion_GB=round(sum(Quantity)/1024,4), Ingestion_TB=round(sum(Quantity)/1048576,8), RecordCount=count() by bin(TimeGenerated, 1d), DataType, Solution\n| extend AvgDaily_GB=round(avgDailyGB,4)\n| extend Pct_of_Avg=round(Ingestion_GB / iif(avgDailyGB==0.0,1.0,avgDailyGB)*100,1)\n| extend SpikeStatus=iff(Ingestion_GB > avgDailyGB*2.0,'CRITICAL SPIKE',iff(Ingestion_GB > avgDailyGB*1.5,'ELEVATED','Normal'))\n| project TimeGenerated, DataType, Solution, Ingestion_MB, Ingestion_GB, Ingestion_TB, AvgDaily_GB, Pct_of_Avg, SpikeStatus, RecordCount\n| order by TimeGenerated desc",
              "size": 1,
              "title": "Daily Spike Detail — {SelectedDataType} (export CSV → cloud team)",
              "timeContextFromParameter": "TimePicker",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "table",
              "gridSettings": {
                "formatters": [
                  {
                    "columnMatch": "TimeGenerated",
                    "formatter": 6
                  },
                  {
                    "columnMatch": "Ingestion_MB",
                    "formatter": 4,
                    "formatOptions": {
                      "palette": "blue",
                      "showBorder": false
                    },
                    "numberFormat": {
                      "unit": 0,
                      "options": {
                        "style": "decimal",
                        "maximumFractionDigits": 2
                      }
                    }
                  },
                  {
                    "columnMatch": "Ingestion_GB",
                    "formatter": 4,
                    "formatOptions": {
                      "palette": "green",
                      "showBorder": false
                    },
                    "numberFormat": {
                      "unit": 0,
                      "options": {
                        "style": "decimal",
                        "maximumFractionDigits": 4
                      }
                    }
                  },
                  {
                    "columnMatch": "Ingestion_TB",
                    "formatter": 4,
                    "formatOptions": {
                      "palette": "orange",
                      "showBorder": false
                    },
                    "numberFormat": {
                      "unit": 0,
                      "options": {
                        "style": "decimal",
                        "maximumFractionDigits": 8
                      }
                    }
                  },
                  {
                    "columnMatch": "AvgDaily_GB",
                    "formatter": 4,
                    "formatOptions": {
                      "palette": "gray",
                      "showBorder": false
                    },
                    "numberFormat": {
                      "unit": 0,
                      "options": {
                        "style": "decimal",
                        "maximumFractionDigits": 4
                      }
                    }
                  },
                  {
                    "columnMatch": "Pct_of_Avg",
                    "formatter": 4,
                    "formatOptions": {
                      "palette": "redGreen",
                      "showBorder": false
                    },
                    "numberFormat": {
                      "unit": 0,
                      "options": {
                        "style": "decimal",
                        "maximumFractionDigits": 1
                      }
                    }
                  },
                  {
                    "columnMatch": "SpikeStatus",
                    "formatter": 18,
                    "formatOptions": {
                      "thresholdsOptions": "colors",
                      "thresholdsGrid": [
                        {
                          "operator": "contains",
                          "thresholdValue": "CRITICAL",
                          "representation": "redBright",
                          "text": "{0}{1}"
                        },
                        {
                          "operator": "contains",
                          "thresholdValue": "ELEVATED",
                          "representation": "yellow",
                          "text": "{0}{1}"
                        },
                        {
                          "operator": "Default",
                          "thresholdValue": null,
                          "representation": "green",
                          "text": "{0}{1}"
                        }
                      ]
                    }
                  }
                ],
                "filter": true,
                "sortBy": [
                  {
                    "itemKey": "TimeGenerated",
                    "sortOrder": 2
                  }
                ],
                "exportAllFields": true,
                "labelSettings": []
              }
            },
            "conditionalVisibility": {
              "parameterName": "SelectedDataType",
              "comparison": "isNotEqualTo",
              "value": ""
            },
            "name": "drilldown-SelectedDataType"
          }
        ]
      },
      "conditionalVisibility": {
        "parameterName": "Tab",
        "comparison": "isEqualTo",
        "value": "First"
      },
      "name": "Ingestion"
    },
